@inject ThemeService ThemeService

<TmToggle @bind-Value="_isDark" Label="Dark Mode" />

@code {
    private bool _isDark;

    protected override async Task OnInitializedAsync()
    {
        _isDark = await ThemeService.GetCurrentThemeAsync() == "dark";
    }

    private async Task ToggleDarkMode(bool value)
    {
        _isDark = value;
        await ThemeService.SetThemeAsync(value ? "dark" : "light");
    }
}

@inherits LayoutComponentBase
@inject ThemeService ThemeService

<TmTopBar BrandTitle="My App" User="@_currentUser"
    OnCommandPalette="() => _paletteOpen = true" OnLogout="HandleLogout">
    <ActionsContent>
        <TmNotificationBell Notifications="@_notifications"
            OnNotificationClick="HandleNotification"
            OnMarkAllRead="MarkAllNotificationsRead" />
    </ActionsContent>
</TmTopBar>

<div style="display: flex; height: calc(100vh - var(--tm-topbar-height));">
    <TmSidebar Items="@_navItems" Collapsed="@_sidebarCollapsed"
        OnToggle="() => _sidebarCollapsed = !_sidebarCollapsed">
        <Header>
            <img src="/logo.svg" alt="Logo" style="height: 32px;" />
        </Header>
    </TmSidebar>

    <main style="flex: 1; overflow: auto; padding: var(--tm-space-6);">
        <TmBreadcrumbs Items="@_breadcrumbs" OnItemClick="NavigateTo" />
        @Body
    </main>
</div>

<TmDrawer @bind-IsOpen="@_drawerOpen" Title="@_drawerTitle" Width="600px">
    @_drawerContent
</TmDrawer>

<TmToastContainer Position="ToastPosition.TopRight" MaxVisible="5" />
<TmCommandPalette @bind-IsOpen="@_paletteOpen" Actions="@_commandActions" />

